/**
 * @param {string[]} chunks
 * @param {string[]} queries
 * @return {number[]}
 */
function solve(chunks, queries) {
    // 1. Concatenate chunks
    const S = chunks.join('');
    const N = S.length;

    // Helper function to check if a character is a lowercase letter
    const isLetter = (char) => {
        const code = char.charCodeAt(0);
        return code >= 'a'.charCodeAt(0) && code <= 'z'.charCodeAt(0);
    };

    // Helper function to check if S[i] is a valid character composing a word
    const isValidChar = (i) => {
        const char = S[i];

        if (isLetter(char)) {
            return true;
        }

        if (char === '-') {
            // Hyphen must be surrounded by letters
            if (i > 0 && i < N - 1) {
                const left = S[i - 1];
                const right = S[i + 1];
                return isLetter(left) && isLetter(right);
            }
            // If it's at the boundary, it cannot be surrounded by letters
            return false;
        }

        // Any other character (space, punctuation, etc.) is a separator
        return false;
    };

    // 2. Extract all words and count them
    const wordCounts = new Map();
    let i = 0;

    while (i < N) {
        if (isValidChar(i)) {
            // Start of a word segment
            let j = i;
            // Consume characters as long as they are valid word characters
            while (j < N && isValidChar(j)) {
                j++;
            }

            // The word is S[i...j-1]
            const word = S.substring(i, j);

            // Update count
            wordCounts.set(word, (wordCounts.get(word) || 0) + 1);

            // Move index i to the position after the found word
            i = j;
        } else {
            // Separator character, skip it
            i++;
        }
    }

    // 3. Answer queries
    const ans = [];
    for (const query of queries) {
        // The problem guarantees queries[i] is a valid word, 
        // so it must be in wordCounts if it appeared.
        ans.push(wordCounts.get(query) || 0);
    }

    return ans;
}

