                return isLetter(left) && isLetter(right);
            }
            // If it's at the boundary, it cannot be surrounded by letters
            return false;
        }

        // Any other character (space, punctuation, etc.) is a separator
        return false;
    };

    // 2. Extract all words and count them
    const wordCounts = new Map();
    let i = 0;

    while (i < N) {
        if (isValidChar(i)) {
            // Start of a word segment
